-- spatial join: find teig that intersect flomareal (200yr)
SELECT t.teigid, t.matrikkelnummertekst, t.kommunenummer
FROM (
  SELECT teigid, matrikkelnummertekst, kommunenummer, omrade FROM matrikkeleneiendomskartteig_36313fab8faa42d99cb779d86d1ca26d.teig WHERE kommunenummer = '4204'
) AS t
WHERE EXISTS (
  SELECT 1 FROM flomsoner_76d14d5fe2fd4a29bfffc266fdcdd820.flomareal f
  WHERE f.gjentaksintervall = 200 AND ST_Intersects(t.omrade, f.omrade)
);

